import{_ as r,o,c as n,a0 as s}from"./chunks/framework.DV6pVIgV.js";const c=JSON.parse('{"title":"監控、合規與治理","description":"","frontmatter":{},"headers":[],"relativePath":"clf-c02/14.md","filePath":"clf-c02/14.md","lastUpdated":1783610848000}'),a={name:"clf-c02/14.md"};function d(g,t,l,e,i,h){return o(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="監控、合規與治理" tabindex="-1">監控、合規與治理 <a class="header-anchor" href="#監控、合規與治理" aria-label="Permalink to &quot;監控、合規與治理&quot;">​</a></h1><p>CloudWatch、CloudTrail、Config、Health 與 Trusted Advisor。</p><h2 id="先備知識" tabindex="-1">先備知識 <a class="header-anchor" href="#先備知識" aria-label="Permalink to &quot;先備知識&quot;">​</a></h2><ul><li><p><strong>監控與可觀測性（Monitoring / Observability）</strong> — 監控就是「持續量測系統健康、出狀況能馬上知道」。要先分清兩種資料：**指標（metrics）**是數字（如 CPU%、請求數），**日誌（logs）**是事件紀錄。這章的 CloudWatch 做的正是這件事，先有這個區分會好懂很多</p><ul><li><a href="https://www.cloudflare.com/learning/performance/what-is-observability/" target="_blank" rel="noreferrer">什麼是可觀測性？（Cloudflare，英文）</a></li><li><a href="https://aws.amazon.com/cloudops/monitoring-and-observability/" target="_blank" rel="noreferrer">監控與可觀測性（AWS，英文）</a></li></ul></li><li><p><strong>API 呼叫（API call）</strong> — 你在 AWS 做的每個操作（主控台點選、CLI、SDK）背後都是一次 API 呼叫。懂這點，才會理解 CloudTrail 為什麼能「記錄帳號裡發生的所有活動」——因為它記的就是這些 API 呼叫</p><ul><li><a href="https://aws.amazon.com/tw/what-is/api/" target="_blank" rel="noreferrer">什麼是 API？（AWS，繁中）</a></li></ul></li><li><p><strong>合規與稽核（Compliance / Audit）</strong> — <strong>合規</strong>＝符合外部標準（如 SOC、PCI DSS、ISO 27001）；<strong>稽核</strong>＝留下證據證明你確實有遵守。這組概念撐起本章的 Config 合規檢查，以及 Artifact（下載報告）、Audit Manager（蒐集證據）</p><ul><li><a href="https://aws.amazon.com/tw/compliance/" target="_blank" rel="noreferrer">AWS 合規計畫（AWS，繁中）</a></li></ul></li></ul><hr><h2 id="為什麼要監控" tabindex="-1">為什麼要監控 <a class="header-anchor" href="#為什麼要監控" aria-label="Permalink to &quot;為什麼要監控&quot;">​</a></h2><p>把服務丟上雲不是結束。你需要持續知道：<strong>資源跑得好不好？有沒有人動了不該動的東西？設定有沒有偏離規範？</strong> 沒有監控，問題往往是「出事了才發現」，而且查不出是誰、什麼時候、改了什麼。</p><hr><h2 id="amazon-cloudwatch-效能與運作監控" tabindex="-1">Amazon CloudWatch（效能與運作監控） <a class="header-anchor" href="#amazon-cloudwatch-效能與運作監控" aria-label="Permalink to &quot;Amazon CloudWatch（效能與運作監控）&quot;">​</a></h2><p>CloudWatch 回答的問題是：「<strong>我的資源現在表現如何？</strong>」它持續收集各種<strong>指標（metrics）</strong>（CPU 使用率、網路流量、請求數…），讓你設<strong>警報</strong>、看<strong>儀表板</strong>、集中<strong>日誌</strong>。</p><p>把它想成系統的<strong>健康監測儀</strong>——隨時顯示心跳、血壓（= CPU、流量等指標），數值異常就觸發警報叫人來。</p><table tabindex="0"><thead><tr><th>功能</th><th>做什麼</th></tr></thead><tbody><tr><td><strong>Metrics（指標）</strong></td><td>收集資源的效能數據（如 EC2 的 CPU 使用率）</td></tr><tr><td><strong>Alarms（警報）</strong></td><td>指標超過門檻就動作，如「CPU &gt; 80% → 發通知 / 觸發 Auto Scaling」</td></tr><tr><td><strong>Dashboards（儀表板）</strong></td><td>把指標視覺化成圖表，一眼看懂系統狀態</td></tr><tr><td><strong>Logs（日誌）</strong></td><td>集中收集應用程式與服務的日誌，方便查詢</td></tr></tbody></table><blockquote><p>📌 <strong>解題方向</strong>：「監控效能 / 設定門檻警報 / 視覺化指標」→ <strong>CloudWatch</strong>。CloudWatch Alarm 也常和 Auto Scaling、SNS 通知搭配。</p></blockquote><hr><h2 id="aws-cloudtrail-活動稽核-誰做了什麼" tabindex="-1">AWS CloudTrail（活動稽核：誰做了什麼） <a class="header-anchor" href="#aws-cloudtrail-活動稽核-誰做了什麼" aria-label="Permalink to &quot;AWS CloudTrail（活動稽核：誰做了什麼）&quot;">​</a></h2><p>CloudTrail 回答的問題是：「<strong>是誰、在什麼時候、從哪裡、做了什麼動作？</strong>」它記錄帳號裡的<strong>每一個 API 呼叫</strong>——因為 AWS 上所有操作（主控台點選、CLI、SDK）本質都是 API 呼叫，所以等於記錄了所有活動。</p><p>把它想成大樓的<strong>監視器錄影 + 門禁日誌</strong>：誰幾點刷卡進來、開了哪扇門、做了什麼，全都留底。</p><ul><li><strong>記錄內容</strong>：誰（哪個身分）、做了什麼動作（哪個 API）、什麼時間、來源 IP</li><li><strong>典型用途</strong>：資安鑑識（「<strong>是誰刪了那個 S3 Bucket？</strong>」）、稽核、合規追溯</li></ul><blockquote><p>📌 <strong>解題方向</strong>：「<strong>追查是誰做了某個操作 / 稽核帳號活動 / API 呼叫紀錄</strong>」→ <strong>CloudTrail</strong>。</p></blockquote><hr><h2 id="aws-config-組態記錄與合規檢查" tabindex="-1">AWS Config（組態記錄與合規檢查） <a class="header-anchor" href="#aws-config-組態記錄與合規檢查" aria-label="Permalink to &quot;AWS Config（組態記錄與合規檢查）&quot;">​</a></h2><p>Config 回答的問題是：「<strong>我的資源設定長什麼樣？什麼時候被改過？符不符合規範？</strong>」它<strong>持續記錄資源的組態（configuration）與每次變更</strong>，還能用 <strong>Config Rules</strong> 自動檢查是否合規。</p><p>把它想成每個房間的<strong>設定快照與變更記錄簿</strong>：現在的擺設是什麼、上週長什麼樣、什麼時候被誰改成現在這樣、有沒有違反規定。</p><ul><li><strong>典型用途</strong>：組態變更追蹤（「這個安全群組上週的規則是什麼？」）、<strong>合規檢查</strong>（「我所有的 EBS 磁碟區都加密了嗎？」「有沒有 S3 Bucket 被設成公開？」）</li></ul><blockquote><p>💡 還記得 M9 的伏筆嗎？「追蹤設定是否合規」就是 <strong>Config</strong>——不是只能下載報告的 Artifact。</p></blockquote><hr><h2 id="🚨-核心辨別-cloudwatch-vs-cloudtrail-vs-config" tabindex="-1">🚨 核心辨別：CloudWatch vs CloudTrail vs Config <a class="header-anchor" href="#🚨-核心辨別-cloudwatch-vs-cloudtrail-vs-config" aria-label="Permalink to &quot;🚨 核心辨別：CloudWatch vs CloudTrail vs Config&quot;">​</a></h2><p>這三個最常一起出現逼你選，因為它們「都在看你的帳號」。用「<strong>回答什麼問題</strong>」來分最清楚：</p><table tabindex="0"><thead><tr><th></th><th>CloudWatch</th><th>CloudTrail</th><th>Config</th></tr></thead><tbody><tr><td><strong>回答的問題</strong></td><td>資源<strong>表現如何</strong>？</td><td><strong>誰做了什麼動作</strong>？</td><td>設定<strong>是什麼 / 變了沒 / 合規嗎</strong>？</td></tr><tr><td><strong>監看對象</strong></td><td>效能<strong>指標</strong>、日誌</td><td><strong>API 呼叫</strong> / 帳號活動</td><td><strong>資源組態</strong>與變更</td></tr><tr><td><strong>類比</strong></td><td>健康監測儀</td><td>監視器 / 門禁日誌</td><td>設定快照與變更記錄簿</td></tr><tr><td><strong>典型用途</strong></td><td>警報、儀表板、效能監控</td><td>稽核、追查誰改了東西</td><td>合規檢查、組態變更追蹤</td></tr></tbody></table><blockquote><p>🚨 一句話記：<strong>效能看 CloudWatch、動作看 CloudTrail、組態與合規看 Config。</strong></p></blockquote><hr><h2 id="其他合規資源" tabindex="-1">其他合規資源 <a class="header-anchor" href="#其他合規資源" aria-label="Permalink to &quot;其他合規資源&quot;">​</a></h2><ul><li><strong>AWS Artifact</strong>：下載 AWS 的合規報告（SOC、PCI DSS、ISO…）—— M9 已介紹</li><li><strong>AWS Audit Manager</strong>：自動蒐集證據、協助跑稽核流程</li></ul><hr><h2 id="aws-organizations-多帳號治理" tabindex="-1">AWS Organizations（多帳號治理） <a class="header-anchor" href="#aws-organizations-多帳號治理" aria-label="Permalink to &quot;AWS Organizations（多帳號治理）&quot;">​</a></h2><p>當你有很多 AWS 帳號（不同團隊、不同專案），需要<strong>集中治理</strong>。AWS Organizations 讓你把多個帳號統一管理：</p><table tabindex="0"><thead><tr><th>功能</th><th>做什麼</th></tr></thead><tbody><tr><td><strong>集中管理 / OU</strong></td><td>把帳號分組成組織單位（OU），統一套政策</td></tr><tr><td><strong>SCP（服務控制政策）</strong></td><td>設帳號的<strong>權限上限</strong>（如「這些帳號只能用特定 Region」）</td></tr><tr><td><strong>合併帳單（Consolidated Billing）</strong></td><td>多帳號<strong>一張帳單</strong>，並可<strong>合併用量享量大折扣</strong></td></tr></tbody></table><blockquote><p>🚨 <strong>合併帳單</strong>是常考點：把多個帳號的用量加總，更容易達到<strong>量大折扣</strong>的門檻，整體更省。這也會在 M11 定價章再遇到。</p><p>📌 <strong>SCP</strong> 設的是上限 / 邊界，不是授權（最終權限 = IAM ∩ SCP）。</p></blockquote><hr><h2 id="aws-health-健康狀態" tabindex="-1">AWS Health（健康狀態） <a class="header-anchor" href="#aws-health-健康狀態" aria-label="Permalink to &quot;AWS Health（健康狀態）&quot;">​</a></h2><p><strong>AWS Health Dashboard</strong> 讓你知道「AWS 服務本身、以及你的資源」的健康狀況，分兩個視角：</p><table tabindex="0"><thead><tr><th>視角</th><th>看什麼</th></tr></thead><tbody><tr><td><strong>服務健康（Service health）</strong></td><td><strong>整體 AWS 服務</strong>的狀態（哪個 Region 的哪個服務出狀況）</td></tr><tr><td><strong>帳號健康（Your account health）</strong></td><td><strong>影響到你自己資源</strong>的事件（如你的某台 EC2 即將進行排程維護）</td></tr></tbody></table><blockquote><p>🚨 <strong>辨別</strong>：「<strong>AWS 哪個服務掛了</strong>」→ 服務健康；「<strong>有什麼事會影響到我的資源</strong>」→ 帳號健康（原 Personal Health Dashboard）。</p></blockquote><hr><h2 id="aws-trusted-advisor-最佳實踐健檢" tabindex="-1">AWS Trusted Advisor（最佳實踐健檢） <a class="header-anchor" href="#aws-trusted-advisor-最佳實踐健檢" aria-label="Permalink to &quot;AWS Trusted Advisor（最佳實踐健檢）&quot;">​</a></h2><p>Trusted Advisor 像一位<strong>自動的最佳實踐稽核員</strong>：掃描你的帳號，對照 AWS 最佳實踐，給出改善建議（紅 = 建議行動、黃 = 建議調查、綠 = 沒問題）。</p><p>它的檢查分成<strong>六大類</strong>：</p><table tabindex="0"><thead><tr><th>類別</th><th>檢查什麼</th></tr></thead><tbody><tr><td><strong>成本最佳化</strong></td><td>找出浪費的閒置資源（沒用的 EIP、低使用率 EC2）</td></tr><tr><td><strong>效能</strong></td><td>找出可提升效能的設定</td></tr><tr><td><strong>安全</strong></td><td>對照安全最佳實踐（如 root 帳號有沒有開 MFA、S3 權限）</td></tr><tr><td><strong>容錯（Fault Tolerance）</strong></td><td>找單點故障（如 RDS 沒開 Multi-AZ、ASG 只在單一 AZ）</td></tr><tr><td><strong>服務限額（Service Limits）</strong></td><td>用量接近帳號配額時提醒你</td></tr><tr><td><strong>卓越營運（Operational Excellence）</strong></td><td>營運管理 hygiene（如是否用 Config 規則、Lambda runtime 是否過時）</td></tr></tbody></table><blockquote><p>💡 <strong>時效注意</strong>：許多舊教材還寫「5 大類」——那是舊的。<strong>「卓越營運」是 2023 年新增的第 6 類</strong>，考試請用 <strong>6 類</strong>。</p><p>🚨 <strong>三個「檢查」服務辨別</strong>：</p><ul><li><strong>Trusted Advisor</strong> = 對照 <strong>AWS 最佳實踐</strong>（涵蓋成本 / 效能 / 安全 / 容錯 / 限額 / 營運）</li><li><strong>Inspector</strong> = 找<strong>軟體漏洞</strong>（M9）</li><li><strong>Config</strong> = 檢查<strong>資源組態是否合規</strong></li></ul></blockquote><h2 id="考試重點整理" tabindex="-1">考試重點整理 <a class="header-anchor" href="#考試重點整理" aria-label="Permalink to &quot;考試重點整理&quot;">​</a></h2><ul><li>🚨 <strong>三大辨別（最重要）</strong>：<strong>CloudWatch</strong>（效能指標 / 警報 / 儀表板）、<strong>CloudTrail</strong>（誰做了什麼——API 活動稽核）、<strong>Config</strong>（設定是什麼 / 變了沒 / 合規嗎）。一句話：<strong>效能看 CloudWatch、動作看 CloudTrail、組態看 Config。</strong></li><li><strong>CloudWatch</strong> Alarm 常搭 Auto Scaling / SNS；<strong>CloudTrail</strong> 用於資安鑑識與稽核；<strong>Config</strong> 搭配 Config Rules 自動合規檢查</li><li><strong>AWS Organizations</strong>：集中治理多帳號、<strong>SCP</strong>（權限上限）、<strong>合併帳單</strong>（量大折扣）</li><li>🚨 <strong>AWS Health</strong>：服務健康（整體 AWS 狀態）vs 帳號健康（影響你資源的事件）</li><li>🚨 <strong>Trusted Advisor</strong>：最佳實踐健檢，<strong>6 大類</strong>（成本、效能、安全、容錯、服務限額、<strong>卓越營運</strong>——第 6 類為 2023 新增，別再背成 5 類）</li><li>🚨 <strong>三個「檢查」服務</strong>：Trusted Advisor（最佳實踐）、Inspector（軟體漏洞）、Config（組態合規）</li></ul><table tabindex="0"><thead><tr><th>情境需求</th><th>答案</th></tr></thead><tbody><tr><td>監控 EC2 的 CPU、設門檻警報</td><td><strong>CloudWatch</strong></td></tr><tr><td>把效能指標做成儀表板</td><td><strong>CloudWatch Dashboards</strong></td></tr><tr><td>追查「是誰刪了那個 Bucket」</td><td><strong>CloudTrail</strong></td></tr><tr><td>稽核帳號的所有 API 活動</td><td><strong>CloudTrail</strong></td></tr><tr><td>檢查「所有 EBS 是否都加密」、追蹤組態變更</td><td><strong>AWS Config</strong></td></tr><tr><td>下載 PCI DSS / SOC 合規報告</td><td><strong>AWS Artifact</strong></td></tr><tr><td>多帳號集中治理、設權限上限</td><td><strong>AWS Organizations（SCP）</strong></td></tr><tr><td>多帳號合併帳單、享量大折扣</td><td><strong>Consolidated Billing</strong></td></tr><tr><td>查 AWS 哪個服務目前有狀況</td><td><strong>AWS Health（服務健康）</strong></td></tr><tr><td>查有什麼事件會影響我的資源</td><td><strong>AWS Health（帳號健康）</strong></td></tr><tr><td>對照最佳實踐做帳號健檢（含成本 / 安全）</td><td><strong>Trusted Advisor</strong></td></tr></tbody></table>',52)])])}const b=r(a,[["render",d]]);export{c as __pageData,b as default};
